<?php declare(strict_types=1);require __DIR__.'/../includes/functions.php';
interface CanRun{public function run():string;}abstract class Animal{abstract public function makeSound():string;}class Dog extends Animal implements CanRun{public function makeSound():string{return 'Woof! Woof!';}public function run():string{return 'Dog is running...';}}class Cat extends Animal{public function makeSound():string{return 'Meow! Meow!';}}
$message='';if($_SERVER['REQUEST_METHOD']==='POST'){$animal=($_POST['animal']??'dog')==='cat'?new Cat():new Dog();$action=(string)($_POST['action']??'sound');$message=$action==='run'?($animal instanceof CanRun?$animal->run():'Cat không triển khai interface CanRun.'):$animal->makeSound();}
$pageTitle='Bài 04 - Abstract';$basePath='..';$current='bai04';require __DIR__.'/../includes/header.php';?>
<div class="crumb"><a href="../index.php">Trang chủ</a> / Bài 04</div><h1>Abstract class và Interface</h1><p class="subtitle">Dog và Cat kế thừa Animal; Dog triển khai CanRun.</p><div class="two"><section class="card"><h2>Chọn hành động</h2><form method="post"><div class="form-grid"><div class="group"><label>Động vật</label><select name="animal"><option value="dog">Dog</option><option value="cat" <?=($_POST['animal']??'')==='cat'?'selected':''?>>Cat</option></select></div><div class="group"><label>Hành động</label><select name="action"><option value="sound">Phát âm thanh</option><option value="run" <?=($_POST['action']??'')==='run'?'selected':''?>>Chạy</option></select></div></div><div class="actions"><button class="btn primary">Thực hiện</button></div></form><div class="note">Interface quy định hành vi bắt buộc; abstract class cung cấp khuôn mẫu chung.</div></section><aside class="card"><div class="result"><h2>Kết quả</h2><?php if($message):?><div class="item"><strong><?=e($message)?></strong></div><?php else:?><p class="muted">Chưa chọn hành động.</p><?php endif;?></div></aside></div><?php require __DIR__.'/../includes/footer.php';?>
